const startTime = Date.now();

const sdContacts = $('GET SuiteDash Contact Count').first().json;
const atClients = $('GET AiTable Client Count').first().json;
const nullScores = $('GET Null Engagement Scores').first().json;
const staleDlq = $('GET Stale DLQ Items').first().json;
const staleFlows = $('GET Stale Onboarding FLOWs').first().json;
const apiUsage = $('GET API Usage').first().json;

const sdCount = sdContacts.data?.length || 0;
const atCount = atClients.data?.records?.length || 0;
const nullScoreCount = nullScores.data?.records?.length || 0;
const staleDlqCount = staleDlq.data?.records?.length || 0;
const staleFlowCount = staleFlows.data?.records?.length || 0;
const apiCallsUsed = parseInt(apiUsage.data?.records?.[0]?.fields?.value || '0');
const apiLimit = parseInt(process.env.SUITEDASH_MONTHLY_API_LIMIT || '2000');
const apiUsagePct = (apiCallsUsed / apiLimit) * 100;

const checks = [];
let passed = 0;
let failed = 0;
let autoFixable = 0;

// Check 1: Contact count match
const countMatch = Math.abs(sdCount - atCount) <= 2; // Allow 2 variance
checks.push({
  name: 'contact_count_match',
  status: countMatch ? 'pass' : 'fail',
  severity: countMatch ? 'none' : 'high',
  auto_fixable: false,
  details: `SuiteDash: ${sdCount}, AiTable: ${atCount}, Diff: ${Math.abs(sdCount - atCount)}`
});
if (countMatch) passed++; else failed++;

// Check 2: Null engagement scores
const scoresOk = nullScoreCount === 0;
checks.push({
  name: 'engagement_scores_populated',
  status: scoresOk ? 'pass' : 'warn',
  severity: scoresOk ? 'none' : 'medium',
  auto_fixable: true,
  details: `${nullScoreCount} active clients missing engagement scores`
});
if (scoresOk) passed++; else { failed++; autoFixable++; }

// Check 3: Stale DLQ items
const dlqOk = staleDlqCount === 0;
checks.push({
  name: 'dlq_not_stale',
  status: dlqOk ? 'pass' : 'fail',
  severity: dlqOk ? 'none' : 'high',
  auto_fixable: true,
  details: `${staleDlqCount} DLQ items unresolved >72 hours`
});
if (dlqOk) passed++; else { failed++; autoFixable++; }

// Check 4: Stale onboarding FLOWs
const flowsOk = staleFlowCount === 0;
checks.push({
  name: 'onboarding_flows_progressing',
  status: flowsOk ? 'pass' : 'warn',
  severity: flowsOk ? 'none' : 'medium',
  auto_fixable: true,
  details: `${staleFlowCount} onboarding FLOWs stalled >14 days`
});
if (flowsOk) passed++; else { failed++; autoFixable++; }

// Check 5: API usage within safe limits
const apiOk = apiUsagePct < 80;
checks.push({
  name: 'api_usage_safe',
  status: apiOk ? 'pass' : (apiUsagePct >= 95 ? 'fail' : 'warn'),
  severity: apiOk ? 'none' : (apiUsagePct >= 95 ? 'critical' : 'high'),
  auto_fixable: true,
  details: `${apiCallsUsed}/${apiLimit} (${apiUsagePct.toFixed(1)}%) API calls used this month`
});
if (apiOk) passed++; else { failed++; autoFixable++; }

const totalChecks = checks.length;
const integrityScore = Math.round((passed / totalChecks) * 100);
const hasCritical = checks.some(c => c.severity === 'critical');
const hasHigh = checks.some(c => c.severity === 'high');
const duration = Math.round((Date.now() - startTime) / 1000);

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    checks_run: totalChecks,
    checks_passed: passed,
    checks_failed: failed,
    anomalies_found: failed,
    auto_fixable_count: autoFixable,
    system_integrity_score: integrityScore,
    run_duration_seconds: duration,
    has_critical: hasCritical,
    has_high: hasHigh,
    needs_alert: hasCritical || hasHigh,
    checks: checks,
    null_score_count: nullScoreCount,
    stale_dlq_count: staleDlqCount,
    stale_flow_count: staleFlowCount,
    api_usage_pct: apiUsagePct
  }
}];

const data = $input.first().json;
const fixes = [];

// Auto-fix 1: Trigger engagement scoring run for null scores
if (data.null_score_count > 0) {
  fixes.push({action: 'trigger_engagement_scoring', reason: `${data.null_score_count} clients missing scores`});
}

// Auto-fix 2: Escalate stale DLQ items
if (data.stale_dlq_count > 0) {
  fixes.push({action: 'escalate_stale_dlq', reason: `${data.stale_dlq_count} DLQ items >72h`});
}

// Auto-fix 3: Send reminders for stale flows
if (data.stale_flow_count > 0) {
  fixes.push({action: 'send_flow_reminders', reason: `${data.stale_flow_count} FLOWs stalled >14d`});
}

// Auto-fix 4: Throttle API if near limit
if (data.api_usage_pct >= 80) {
  fixes.push({action: 'throttle_api_workflows', reason: `API at ${data.api_usage_pct.toFixed(1)}% of limit`});
}

return [{json: {...data, auto_fixes_applied: fixes}}];

